fn has_role(user: &AuthenticatedUser, role: &str) -> bool {
    user.roles.iter().any(|r| r == role)
}

fn has_any_role(user: &AuthenticatedUser, roles: &[&str]) -> bool {
    roles.iter().any(|role| has_role(user, role))
}

/// Check if user can access invoices for the given tenant
fn can_access_tenant(user: &AuthenticatedUser, tenant_id: Uuid) -> bool {
    user.tenant_id == tenant_id
}

/// Check if user can view the specific invoice
fn can_view_invoice(user: &AuthenticatedUser, invoice: &Invoice) -> bool {
    // Must belong to the same tenant
    if !can_access_tenant(user, invoice.tenant_id) {
        return false;
    }

    // Admins and finance roles can view any invoice in their tenant
    if has_any_role(user, &["admin", "finance", "manager"]) {
        return true;
    }

    // Regular users can only view their own invoices
    if has_role(user, "user") && invoice.owner_id == user.user_id {
        return true;
    }

    false
}

/// Check if user can update the specific invoice
fn can_update_invoice(user: &AuthenticatedUser, invoice: &Invoice) -> bool {
    if !can_access_tenant(user, invoice.tenant_id) {
        return false;
    }

    // Only admin and finance can update invoices
    if has_any_role(user, &["admin", "finance"]) {
        return true;
    }

    // Owners can update only if invoice is in draft status
    if invoice.owner_id == user.user_id && invoice.status == "draft" {
        return true;
    }

    false
}

/// Validate which fields the user is allowed to update
fn validate_updatable_fields(
    user: &AuthenticatedUser,
    invoice: &Invoice,
    update: &InvoiceUpdateRequest,
) -> Result<(), String> {
    // Check status transitions
    if let Some(ref new_status) = update.status {
        let valid_transition = match (invoice.status.as_str(), new_status.as_str()) {
            ("draft", "submitted") => {
                // Owner, admin, or finance can submit
                invoice.owner_id == user.user_id || has_any_role(user, &["admin", "finance"])
            }
            ("submitted", "approved") | ("submitted", "rejected") => {
                // Only admin or finance can approve/reject
                has_any_role(user, &["admin", "finance"])
            }
            ("approved", "paid") => {
                // Only finance can mark as paid
                has_role(user, "finance") || has_role(user, "admin")
            }
            ("draft", "cancelled") | ("submitted", "cancelled") => {
                // Owner, admin, or finance can cancel draft/submitted
                invoice.owner_id == user.user_id || has_any_role(user, &["admin", "finance"])
            }
            _ => false,
        };

        if !valid_transition {
            return Err(format!(
                "Status transition from '{}' to '{}' is not allowed for your role",
                invoice.status, new_status
            ));
        }
    }

    // internal_notes: only admin and finance
    if update.internal_notes.is_some() && !has_any_role(user, &["admin", "finance"]) {
        return Err("Only admin and finance roles can update internal_notes".to_string());
    }

    // cost_center: only admin and finance
    if update.cost_center.is_some() && !has_any_role(user, &["admin", "finance"]) {
        return Err("Only admin and finance roles can update cost_center".to_string());
    }

    // amount: only updatable in draft status, by owner or admin/finance
    if update.amount.is_some() {
        if invoice.status != "draft" {
            return Err("Amount can only be updated when invoice is in draft status".to_string());
        }
        if invoice.owner_id != user.user_id && !has_any_role(user, &["admin", "finance"]) {
            return Err("Only the invoice owner or admin/finance can update the amount".to_string());
        }
    }

    // description: updatable in draft by owner, or by admin/finance in any status
    if update.description.is_some() {
        if invoice.status != "draft" && !has_any_role(user, &["admin", "finance"]) {
            return Err(
                "Description can only be updated in draft status unless you are admin/finance"
                    .to_string(),
            );
        }
    }

    Ok(())
}

