    use super::*;

    fn make_user(roles: Vec<&str>, tenant_id: Uuid, user_id: Uuid) -> AuthenticatedUser {
        AuthenticatedUser {
            user_id,
            tenant_id,
            roles: roles.into_iter().map(String::from).collect(),
        }
    }

    fn make_invoice(tenant_id: Uuid, owner_id: Uuid, status: &str) -> Invoice {
        Invoice {
            id: Uuid::new_v4(),
            tenant_id,
            owner_id,
            invoice_number: "INV-001".to_string(),
            amount: 100.0,
            currency: "USD".to_string(),
            status: status.to_string(),
            description: Some("Test invoice".to_string()),
            created_at: chrono::Utc::now().naive_utc(),
            updated_at: chrono::Utc::now().naive_utc(),
            internal_notes: Some("Internal note".to_string()),
            cost_center: Some("CC-100".to_string()),
        }
    }

    #[test]
    fn test_tenant_isolation() {
        let tenant_a = Uuid::new_v4();
        let tenant_b = Uuid::new_v4();
        let user = make_user(vec!["admin"], tenant_a, Uuid::new_v4());

        assert!(can_access_tenant(&user, tenant_a));
        assert!(!can_access_tenant(&user, tenant_b));
    }

    #[test]
    fn test_admin_can_view_any_invoice_in_tenant() {
        let tenant_id = Uuid::new_v4();
        let user = make_user(vec!["admin"], tenant_id, Uuid::new_v4());
        let invoice = make_invoice(tenant_id, Uuid::new_v4(), "submitted");

        assert!(can_view_invoice(&user, &invoice));
    }

